events.inlineCode:
var rs = runtimeScene;
var g = rs.getGame().getVariables();
var im = rs.getGame().getInputManager();
function one(n){var a=rs.getObjects(n);return a.length?a[0]:null;}
var ids = im.getStartedTouchIdentifiers();
for (var k=0;k<ids.length;k++){
  var x=im.getTouchX(ids[k]), y=im.getTouchY(ids[k]);
  function hit(n){var o=one(n);return o&&o.insideObject(x,y);}
  if (hit("BtnNormal")) { g.get("g_encounter").setString("normal"); gdjs.evtTools.sound.playSound(rs,"select.wav",false,100,1); gdjs.evtTools.runtimeScene.replaceScene(rs,"Battle",true); }
  else if (hit("BtnHard")) { g.get("g_encounter").setString("hard"); gdjs.evtTools.sound.playSound(rs,"select.wav",false,100,1); gdjs.evtTools.runtimeScene.replaceScene(rs,"Battle",true); }
  else if (hit("BtnBoss")) { g.get("g_encounter").setString("boss"); gdjs.evtTools.sound.playSound(rs,"select.wav",false,100,1); gdjs.evtTools.runtimeScene.replaceScene(rs,"Battle",true); }
}

var rs = runtimeScene;
var DATA = {"party": [{"id": "warrior", "name": "戰士", "sprite": "warrior", "hp": 130, "mp": 8, "atk": 24, "def": 15, "spd": 9, "skills": ["heavy_slash"]}, {"id": "whitemage", "name": "白魔", "sprite": "whitemage", "hp": 85, "mp": 42, "atk": 11, "def": 9, "spd": 11, "skills": ["cure", "curaga"]}, {"id": "blackmage", "name": "黑魔", "sprite": "blackmage", "hp": 72, "mp": 48, "atk": 9, "def": 8, "spd": 12, "skills": ["fire", "blizzard", "thunder", "firaga"]}], "enemies": [{"id": "goblin", "name": "哥布林", "sprite": "goblin", "hp": 46, "atk": 15, "def": 6, "spd": 8, "exp": 12, "gold": 8}, {"id": "imp", "name": "小惡魔", "sprite": "imp", "hp": 38, "atk": 18, "def": 4, "spd": 13, "exp": 14, "gold": 10}, {"id": "skeleton", "name": "骷髏兵", "sprite": "skeleton", "hp": 60, "atk": 17, "def": 9, "spd": 7, "exp": 18, "gold": 14}, {"id": "demon", "name": "魔王", "sprite": "demon", "hp": 320, "atk": 30, "def": 14, "spd": 10, "exp": 200, "gold": 300}], "skills": [{"id": "heavy_slash", "name": "強力斬", "mp": 4, "power": 26, "target": "enemy", "kind": "damage", "element": "physical"}, {"id": "fire", "name": "火焰", "mp": 6, "power": 30, "target": "enemy", "kind": "damage", "element": "fire"}, {"id": "blizzard", "name": "冰結", "mp": 6, "power": 30, "target": "enemy", "kind": "damage", "element": "ice"}, {"id": "thunder", "name": "雷擊", "mp": 8, "power": 38, "target": "enemy", "kind": "damage", "element": "thunder"}, {"id": "firaga", "name": "火焰暴", "mp": 18, "power": 34, "target": "all_enemies", "kind": "damage", "element": "fire"}, {"id": "cure", "name": "治療", "mp": 5, "power": 48, "target": "ally", "kind": "heal"}, {"id": "curaga", "name": "群體治療", "mp": 14, "power": 34, "target": "all_allies", "kind": "heal"}], "items": [{"id": "potion", "name": "藥水", "sprite": "potion", "kind": "heal", "power": 55, "count": 5}], "encounters": {"normal": ["goblin", "goblin", "imp"], "hard": ["skeleton", "imp", "goblin", "goblin"], "boss": ["demon"]}};
var NATIVE = {"warrior": [16, 28], "whitemage": [16, 28], "blackmage": [16, 28], "goblin": [16, 16], "imp": [16, 16], "skeleton": [16, 16], "demon": [32, 36]};

function A(n){return rs.getObjects(n);}
function one(n){var a=rs.getObjects(n);return a.length?a[0]:null;}
function bySlot(n,slot){var a=rs.getObjects(n);for(var i=0;i<a.length;i++){if(a[i].getVariables().get("slot").getAsNumber()===slot)return a[i];}return null;}
function sfx(n){gdjs.evtTools.sound.playSound(rs,n,false,100,1);}
function findSkill(id){for(var i=0;i<DATA.skills.length;i++){if(DATA.skills[i].id===id)return DATA.skills[i];}return null;}

if(!rs.__b){ initB(); }
var b = rs.__b;
try { window.__B = b; } catch(e) {}
var dt = rs.getElapsedTime()/1000;

// 收集本幀點擊
var im = rs.getGame().getInputManager();
var cs = [];
var ids = im.getStartedTouchIdentifiers();
for(var i=0;i<ids.length;i++){ cs.push([im.getTouchX(ids[i]), im.getTouchY(ids[i])]); }
function clickOn(name){ var o=one(name); if(!o||o.isHidden())return false; for(var i=0;i<cs.length;i++){ if(o.insideObject(cs[i][0],cs[i][1]))return true;} return false; }

// ---- 狀態機 ----
if(b.state==="msg"){
  b.msgTimer -= dt;
  if(b.msgTimer<=0){
    if(!checkEnd()){
      if(b.after==="start"){ beginRound(); }
      else { nextTurn(); }
    }
  }
} else if(b.state==="menu"){
  if(clickOn("CmdAtk")){ sfx("select.wav"); b.pending={type:"attack"}; b.state="target"; }
  else if(clickOn("CmdMag")){ sfx("select.wav"); b.state="magic"; }
  else if(clickOn("CmdItem")){ sfx("select.wav"); b.state="item"; }
  else if(clickOn("CmdFlee")){ sfx("select.wav"); if(Math.random()<0.6){ gdjs.evtTools.runtimeScene.replaceScene(rs,"Menu",true); return; } else { say(b.actor.name+" 逃跑失敗！","advance"); } }
} else if(b.state==="magic"){
  if(clickOn("BtnBack")){ sfx("select.wav"); b.state="menu"; }
  else { for(var i=0;i<5;i++){ if(clickOn("Spell"+i)){ var sid=b.actor.skills[i]; if(!sid)break; var sk=findSkill(sid); if(b.actor.mp<sk.mp){ say("MP 不足！","stay"); break; } sfx("select.wav"); b.pending={type:"skill",skill:sk};
      if(sk.target==="enemy"){ b.state="target"; }
      else if(sk.target==="ally"){ b.state="target_ally"; }
      else { applyToAll(sk.target); }
      break; } } }
} else if(b.state==="item"){
  if(clickOn("BtnBack")){ sfx("select.wav"); b.state="menu"; }
  else if(clickOn("Item0")){ var it=DATA.items[0]; if(it.count<=0){ say("藥水用完了！","stay"); } else { sfx("select.wav"); b.pending={type:"item",item:it}; b.state="target_ally"; } }
} else if(b.state==="target"){
  if(clickOn("BtnBack")){ sfx("select.wav"); b.state="menu"; }
  else { for(var i=0;i<b.enemies.length;i++){ var e=b.enemies[i]; if(!e.alive)continue; for(var j=0;j<cs.length;j++){ if(e.obj.insideObject(cs[j][0],cs[j][1])){ applyTo([e]); return; } } } }
} else if(b.state==="target_ally"){
  if(clickOn("BtnBack")){ sfx("select.wav"); b.state="menu"; }
  else { for(var i=0;i<b.party.length;i++){ var p=b.party[i]; if(!p.alive)continue; var hitp=false; for(var j=0;j<cs.length;j++){ if(p.obj.insideObject(cs[j][0],cs[j][1])){hitp=true;} } var row=bySlot0("Status",p.slot); if(row){ for(var j=0;j<cs.length;j++){ if(row.insideObject(cs[j][0],cs[j][1])){hitp=true;} } } if(hitp){ applyTo([p]); return; } } }
} else if(b.state==="enemy"){
  b.enemyDelay -= dt;
  if(b.enemyDelay<=0){ enemyAct(); }
} else if(b.state==="win" || b.state==="lose"){
  if(clickOn("BtnRestart")){ sfx("select.wav"); gdjs.evtTools.runtimeScene.replaceScene(rs,"Battle",true); return; }
  if(clickOn("BtnMenu")){ sfx("select.wav"); gdjs.evtTools.runtimeScene.replaceScene(rs,"Menu",true); return; }
}
refresh();
return;

// ================= functions =================
function bySlot0(name,slot){ return bySlot(name,slot); }

function mkCombatant(tpl, side, slot){
  return { id:tpl.id, name:tpl.name, sprite:tpl.sprite, side:side, slot:slot,
           hp:tpl.hp, maxhp:tpl.hp, mp:(tpl.mp||0), maxmp:(tpl.mp||0),
           atk:tpl.atk, def:tpl.def, spd:tpl.spd, skills:(tpl.skills||[]).slice(),
           exp:(tpl.exp||0), gold:(tpl.gold||0), alive:true, obj:null };
}

function layoutOne(cbt){
  var objName = cbt.side==="party" ? "Hero" : "Foe";
  var o = bySlot(objName, cbt.slot);
  cbt.obj = o;
  o.setAnimationName(cbt.sprite);
  var nat = NATIVE[cbt.sprite] || [16,16];
  var targetH = cbt.side==="party" ? 140 : (cbt.sprite==="demon" ? 175 : 100);
  var w = Math.round(nat[0]/nat[1]*targetH);
  o.setWidth(w); o.setHeight(targetH);
  // 位置：以 slot 中心排列
  var cx, cy;
  if(cbt.side==="party"){ var PX=[ [1060,210],[1060,345],[1060,480] ]; cx=PX[cbt.slot][0]; cy=PX[cbt.slot][1]; o.flipX(true); }
  else { var EX=[ [320,270],[480,350],[290,450],[470,230] ]; if(b.enemies.length===1){cx=360;cy=330;} else {cx=EX[cbt.slot][0]; cy=EX[cbt.slot][1];} o.flipX(false); }
  o.setX(cx - w/2); o.setY(cy - targetH/2);
  o.setColor("255;255;255"); o.hide(false);
}

function initB(){
  rs.__b = {};
  b = rs.__b;
  var enc = rs.getGame().getVariables().get("g_encounter").getAsString() || "normal";
  var encList = DATA.encounters[enc] || DATA.encounters.normal;
  // 重置道具數量
  for(var i=0;i<DATA.items.length;i++){ DATA.items[i].count = DATA.items[i]._max || DATA.items[i].count; DATA.items[i]._max = DATA.items[i]._max || DATA.items[i].count; }
  b.party = [];
  for(var i=0;i<DATA.party.length && i<3;i++){ b.party.push(mkCombatant(DATA.party[i],"party",i)); }
  b.enemies = [];
  var tplById = {}; for(var i=0;i<DATA.enemies.length;i++){ tplById[DATA.enemies[i].id]=DATA.enemies[i]; }
  for(var i=0;i<encList.length && i<4;i++){ b.enemies.push(mkCombatant(tplById[encList[i]],"enemy",i)); }
  // 全部建好後才排版（避免 layoutOne 用到建構中的長度）
  for(var i=0;i<b.party.length;i++){ layoutOne(b.party[i]); }
  for(var i=0;i<b.enemies.length;i++){ layoutOne(b.enemies[i]); }
  // 隱藏未使用的 slot 實例
  for(var s=b.party.length;s<3;s++){ var o=bySlot("Hero",s); if(o)o.hide(true); }
  for(var s=b.enemies.length;s<4;s++){ var o=bySlot("Foe",s); if(o)o.hide(true); }
  b.round=0; b.turnIdx=0; b.order=[]; b.state="msg"; b.msg="戰鬥開始！"; b.msgTimer=1.0; b.after="start"; b.pending=null;
}

function beginRound(){
  b.round++;
  var all = b.party.concat(b.enemies).filter(function(c){return c.alive;});
  all.sort(function(x,y){ return (y.spd - x.spd) || (Math.random()-0.5); });
  b.order = all;
  b.turnIdx = -1;
  nextTurn();
}

function nextTurn(){
  b.turnIdx++;
  while(b.turnIdx < b.order.length && !b.order[b.turnIdx].alive){ b.turnIdx++; }
  if(b.turnIdx >= b.order.length){ beginRound(); return; }
  b.actor = b.order[b.turnIdx];
  if(b.actor.side==="party"){ b.state="menu"; }
  else { b.state="enemy"; b.enemyDelay=0.5; }
}

function physical(a,t){
  var base = a.atk*2 - t.def; if(base<1)base=1;
  var crit = Math.random()<0.0625;
  var v = 0.85 + Math.random()*0.15;
  return { dmg: Math.max(1, Math.round(base*v*(crit?1.5:1))), crit:crit };
}
function magical(a,sk,t){
  var base = sk.power + Math.round(a.atk*0.5) - Math.round(t.def*0.5); if(base<1)base=1;
  var v = 0.85 + Math.random()*0.15;
  return Math.max(1, Math.round(base*v));
}

function killCheck(t){ if(t.hp<=0){ t.hp=0; t.alive=false; if(t.obj) t.obj.hide(true); } }

function applyTo(targets){
  var act = b.actor, p = b.pending, msg="";
  if(p.type==="attack"){
    var t=targets[0]; var r=physical(act,t); t.hp-=r.dmg; sfx("atk.wav"); sfx("hurt.wav");
    msg = act.name+" 攻擊 "+t.name+"，造成 "+r.dmg+" 傷害"+(r.crit?"（會心一擊！）":""); killCheck(t);
  } else if(p.type==="skill"){
    var sk=p.skill; act.mp-=sk.mp;
    if(sk.kind==="damage"){ var t=targets[0]; var d=magical(act,sk,t); t.hp-=d; sfx("magic.wav"); sfx("hurt.wav");
      msg=act.name+" 施放「"+sk.name+"」，"+t.name+" 受到 "+d+" 傷害"; killCheck(t); }
    else { var t=targets[0]; var before=t.hp; t.hp=Math.min(t.maxhp, t.hp+sk.power); sfx("heal.wav");
      msg=act.name+" 施放「"+sk.name+"」，"+t.name+" 恢復 "+(t.hp-before)+" HP"; }
  } else if(p.type==="item"){
    var it=p.item; it.count--; var t=targets[0]; var before=t.hp; t.hp=Math.min(t.maxhp,t.hp+it.power); sfx("heal.wav");
    msg=act.name+" 使用「"+it.name+"」，"+t.name+" 恢復 "+(t.hp-before)+" HP";
  }
  say(msg,"advance");
}

function applyToAll(targetKind){
  var act=b.actor, sk=b.pending.skill, msg="";
  act.mp-=sk.mp;
  if(targetKind==="all_enemies"){
    var list=b.enemies.filter(function(c){return c.alive;});
    var total=0; for(var i=0;i<list.length;i++){ var d=magical(act,sk,list[i]); list[i].hp-=d; total+=d; killCheck(list[i]); }
    sfx("magic.wav"); sfx("hurt.wav"); msg=act.name+" 施放「"+sk.name+"」！全體敵人共受到 "+total+" 傷害";
  } else {
    var list=b.party.filter(function(c){return c.alive;});
    for(var i=0;i<list.length;i++){ list[i].hp=Math.min(list[i].maxhp, list[i].hp+sk.power); }
    sfx("heal.wav"); msg=act.name+" 施放「"+sk.name+"」！全體隊友恢復 "+sk.power+" HP";
  }
  say(msg,"advance");
}

function enemyAct(){
  var act=b.actor;
  var alive=b.party.filter(function(c){return c.alive;});
  if(alive.length===0){ checkEnd(); return; }
  var t=alive[Math.floor(Math.random()*alive.length)];
  var r=physical(act,t); t.hp-=r.dmg; sfx("atk.wav"); sfx("hurt.wav");
  var msg=act.name+" 攻擊 "+t.name+"，造成 "+r.dmg+" 傷害"+(r.crit?"（會心一擊！）":"");
  killCheck(t);
  say(msg,"advance");
}

function say(msg, after){ b.msg=msg; b.msgTimer=(after==="stay"?0.7:0.95); b.state="msg"; b.after=(after==="stay"?"stay":after); if(after==="stay"){ b._resume=("menu"); } }

function checkEnd(){
  var pa=b.party.filter(function(c){return c.alive;}).length;
  var ea=b.enemies.filter(function(c){return c.alive;}).length;
  if(ea===0){ var exp=0,gold=0; for(var i=0;i<b.enemies.length;i++){exp+=b.enemies[i].exp;gold+=b.enemies[i].gold;} b.state="win"; b.winMsg="獲得 "+exp+" 經驗值 · "+gold+" 金幣"; sfx("win.wav"); return true; }
  if(pa===0){ b.state="lose"; b.winMsg="隊伍全滅…"; sfx("lose.wav"); return true; }
  return false;
}

function setTxt(name,s){ var o=one(name); if(o)o.setString(s); }
function setCol(name,c){ var o=one(name); if(o)o.setColor(c); }
function showObj(name,vis){ var o=one(name); if(o)o.hide(!vis); }

function refresh(){
  // 若 stay 訊息結束，回到指令
  if(b.state==="msg" && b.after==="stay" && b.msgTimer<=0){ b.state="menu"; }
  // 狀態列
  for(var i=0;i<3;i++){
    var row="Status"+i;
    if(i<b.party.length){ var p=b.party[i]; showObj(row,true);
      setTxt(row, p.name+"   HP "+Math.max(0,p.hp)+"/"+p.maxhp+"   MP "+p.mp+"/"+p.maxmp);
      setCol(row, !p.alive?"120;120;130":(b.actor && b.actor===p && b.state!=="msg" ? "255;235;120":"255;255;255"));
    } else showObj(row,false);
  }
  // 敵人名稱
  for(var i=0;i<4;i++){
    var nm="FoeName"+i;
    if(i<b.enemies.length && b.enemies[i].alive){ var e=b.enemies[i]; showObj(nm,true); setTxt(nm,e.name);
      var o=one(nm); if(o&&e.obj){ o.setX(e.obj.getX()+e.obj.getWidth()/2-100); o.setY(e.obj.getY()+e.obj.getHeight()+4); }
      setCol(nm, b.state==="target" ? "255;235;120":"235;235;245");
    } else showObj(nm,false);
  }
  // 指令視窗
  var heroTurn = b.actor && b.actor.side==="party";
  var showCmd = heroTurn && b.state==="menu";
  var showMag = heroTurn && b.state==="magic";
  var showItem = heroTurn && b.state==="item";
  var showBack = heroTurn && (b.state==="magic"||b.state==="item"||b.state==="target"||b.state==="target_ally");
  showObj("CmdAtk",showCmd); showObj("CmdMag",showCmd); showObj("CmdItem",showCmd); showObj("CmdFlee",showCmd);
  showObj("BtnBack",showBack);
  for(var i=0;i<5;i++){
    var sp="Spell"+i;
    if(showMag && b.actor.skills[i]){ var sk=findSkill(b.actor.skills[i]); showObj(sp,true);
      setTxt(sp, sk.name+"  ("+sk.mp+" MP)"); setCol(sp, b.actor.mp>=sk.mp?"255;255;255":"120;120;130");
    } else showObj(sp,false);
  }
  showObj("Item0", showItem); showObj("Item1", false);
  if(showItem){ var it=DATA.items[0]; setTxt("Item0", it.name+"  x"+it.count); setCol("Item0", it.count>0?"255;255;255":"120;120;130"); }
  // 游標指向當前英雄
  var cur=one("Cursor");
  if(cur){ if(heroTurn && b.state!=="msg" && b.actor.obj){ cur.hide(false); cur.setX(b.actor.obj.getX()+b.actor.obj.getWidth()+6); cur.setY(b.actor.obj.getY()+b.actor.obj.getHeight()/2-20); } else cur.hide(true); }
  // 訊息文字
  var mt="";
  if(b.state==="msg") mt=b.msg;
  else if(b.state==="menu") mt=b.actor.name+" 的回合 — 選擇指令";
  else if(b.state==="magic") mt="選擇魔法";
  else if(b.state==="item") mt="選擇道具";
  else if(b.state==="target") mt="選擇攻擊目標";
  else if(b.state==="target_ally") mt="選擇對象";
  else if(b.state==="enemy") mt=b.actor.name+" 的回合…";
  setTxt("MsgText", mt);
  // 結算畫面
  var end = (b.state==="win"||b.state==="lose");
  for(var i=0;i<["OverlayBg", "ResultTitle", "ResultMsg", "BtnRestart", "TxtRestart", "BtnMenu", "TxtMenu"].length;i++){ showObj(["OverlayBg", "ResultTitle", "ResultMsg", "BtnRestart", "TxtRestart", "BtnMenu", "TxtMenu"][i], end); }
  if(end){ setTxt("ResultTitle", b.state==="win"?"勝　利！":"戰　敗"); setCol("ResultTitle", b.state==="win"?"255;235;140":"255;150;150"); setTxt("ResultMsg", b.winMsg); }
}
